const VideoCarousel = () => {
  const [activeVideo, setActiveVideo] = useState<number | null>(null);
  const [scrollPaused, setScrollPaused] = useState(false);
  const videoRefs = useRef<{[key: number]: HTMLVideoElement | null}>({});
  const scrollRef = useRef<HTMLDivElement>(null);
  const scrollX = useRef(0);
  const animFrame = useRef<number | null>(null);
  const CARD_WIDTH = 340;
  const GAP = 24;
  const SPEED = 0.6;

  const animate = useCallback(() => {
    if (!scrollRef.current || scrollPaused) return;
    scrollX.current += SPEED;
    const totalWidth = MUKBANG_VIDEOS.length * (CARD_WIDTH + GAP);
    if (scrollX.current >= totalWidth) scrollX.current = 0;
    scrollRef.current.style.transform = `translateX(-${scrollX.current}px)`;
    animFrame.current = requestAnimationFrame(animate);
  }, [scrollPaused]);

  useEffect(() => {
    if (!scrollPaused) {
      animFrame.current = requestAnimationFrame(animate);
    } else {
      if (animFrame.current) cancelAnimationFrame(animFrame.current);
    }
    return () => { if (animFrame.current) cancelAnimationFrame(animFrame.current); };
  }, [scrollPaused, animate]);

  const handleVideoClick = (id: number) => {
    if (activeVideo === id) {
      // Pause it
      videoRefs.current[id]?.pause();
      setActiveVideo(null);
      setScrollPaused(false);
    } else {
      // Stop any playing video
      if (activeVideo !== null) {
        videoRefs.current[activeVideo]?.pause();
      }
      setActiveVideo(id);
      setScrollPaused(true);
      setTimeout(() => {
        const vid = videoRefs.current[id];
        if (vid) {
          vid.currentTime = 0;
          vid.play().catch(() => {});
        }
      }, 50);
    }
  };

  const handleVideoEnded = (id: number) => {
    setActiveVideo(null);
    setScrollPaused(false);
  };

  const doubled = [...MUKBANG_VIDEOS, ...MUKBANG_VIDEOS];

  return (
    <div className="w-full overflow-hidden">
      <div className="relative">
        <div ref={scrollRef} className="flex gap-6" style={{width: 'max-content'}}>
          {doubled.map((video, idx) => {
            const isActive = activeVideo === video.id;
            return (
              <div
                key={`${video.id}-${idx}`}
                onClick={() => handleVideoClick(video.id)}
                className="flex-shrink-0 cursor-pointer group relative"
                style={{width: CARD_WIDTH}}
              >
                <div className="relative aspect-video rounded-2xl overflow-hidden border border-white/10">
                  {/* Thumbnail shown when not active */}
                  {!isActive && (
                    <img
                      src={video.thumb}
                      alt={video.title}
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
                    />
                  )}
                  {/* Video element */}
                  <video
                    ref={el => { videoRefs.current[video.id] = el; }}
                    className={`w-full h-full object-cover absolute inset-0 ${isActive ? 'opacity-100' : 'opacity-0'}`}
                    loop={false}
                    muted
                    playsInline
                    onEnded={() => handleVideoEnded(video.id)}
                  >
                    <source src={video.url} type="video/mp4" />
                  </video>
                  {/* Overlay */}
                  <div className={`absolute inset-0 bg-black/50 flex items-center justify-center transition-opacity ${isActive ? 'opacity-0' : 'opacity-100 group-hover:opacity-80'}`}>
                    <div className="w-14 h-14 bg-red-600 rounded-full flex items-center justify-center shadow-xl">
                      <Play fill="white" size={22} className="ml-1" />
                    </div>
                  </div>
                  {isActive && (
                    <div className="absolute top-3 right-3 bg-red-600 rounded-full p-2">
                      <Pause size={14} className="text-white" />
                    </div>
                  )}
                </div>
                <div className="mt-4 px-1">
                  <h4 className="text-white font-black uppercase tracking-tight text-lg">{video.title}</h4>
                  <p className="text-white/40 text-sm mt-1">{video.desc}</p>
                </div>
              </div>
            );
          })}
        </div>
        {/* Fade edges */}
        <div className="absolute left-0 top-0 bottom-0 w-20 bg-gradient-to-r from-black to-transparent pointer-events-none z-10" />
        <div className="absolute right-0 top-0 bottom-0 w-20 bg-gradient-to-l from-black to-transparent pointer-events-none z-10" />
      </div>
      <p className="text-center text-white/20 text-xs uppercase tracking-widest mt-8 font-bold">Click any video to watch • Auto-resumes on finish</p>
    </div>
  );
};

