const FlameCursor = () => {
  const [mousePos, setMousePos] = useState({ x: -100, y: -100 });
  const [isPointer, setIsPointer] = useState(false);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
      const target = e.target as HTMLElement;
      const isClickable = window.getComputedStyle(target).cursor === 'pointer' || 
                         target.tagName === 'BUTTON' || 
                         target.tagName === 'A';
      setIsPointer(isClickable);
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  return (
    <motion.div
      className="fixed top-0 left-0 pointer-events-none z-[9999] mix-blend-screen"
      animate={{ x: mousePos.x, y: mousePos.y, scale: isPointer ? 1.5 : 1 }}
      transition={{ type: 'spring', damping: 30, stiffness: 400, mass: 0.2 }}
    >
      <div className="relative -translate-x-1/2 -translate-y-[80%]">
        <motion.div animate={{ scale: [1, 1.2, 0.9, 1.1, 1], rotate: [-5, 5, -3, 3, 0], opacity: [0.4, 0.6, 0.4] }} transition={{ duration: 0.8, repeat: Infinity, ease: "linear" }} className="absolute inset-0 w-12 h-16 bg-red-600 rounded-full blur-2xl -translate-x-1/4 -translate-y-1/4" />
        <motion.div animate={{ scale: [1, 1.1, 0.9, 1.05, 1], rotate: [-2, 2, -1, 1, 0], y: [0, -4, 0] }} transition={{ duration: 0.6, repeat: Infinity, ease: "linear" }} className="w-8 h-12 bg-red-600 rounded-full blur-md opacity-80" />
        <motion.div animate={{ scale: [1, 1.2, 0.8, 1.1, 1], y: [0, -6, 0] }} transition={{ duration: 0.4, repeat: Infinity, ease: "linear" }} className="absolute inset-0 w-6 h-10 bg-orange-500 rounded-full blur-sm m-auto opacity-90" />
        <motion.div animate={{ scale: [1, 1.3, 0.9, 1.2, 1] }} transition={{ duration: 0.3, repeat: Infinity, ease: "linear" }} className="absolute inset-0 w-4 h-6 bg-yellow-200 rounded-full blur-[2px] m-auto" />
        {[...Array(4)].map((_, i) => (
          <motion.div key={i} initial={{ opacity: 0, y: 0, x: 0 }} animate={{ opacity: [0, 1, 0], y: -60 - Math.random() * 60, x: (Math.random() - 0.5) * 40, scale: [0, 1.5, 0] }} transition={{ duration: 1 + Math.random(), repeat: Infinity, delay: i * 0.3 }} className="absolute top-0 left-1/2 w-1 h-1 bg-yellow-400 rounded-full blur-[0.5px]" />
        ))}
      </div>
    </motion.div>
  );
};

const Modal = ({ isOpen, onClose }: { isOpen: boolean; onClose: () => void }) => {
  if (!isOpen) return null;
  const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const form = e.currentTarget;
    const restaurant = (form.querySelector('[name="restaurant"]') as HTMLInputElement)?.value;
    const email = (form.querySelector('[name="email"]') as HTMLInputElement)?.value;
    const pkg = (form.querySelector('[name="package"]') as HTMLSelectElement)?.value;
    const msg = (form.querySelector('[name="message"]') as HTMLTextAreaElement)?.value;
    window.location.href = `mailto:sales@mukbangmedia.com?subject=New Inquiry — ${restaurant}&body=Restaurant: ${restaurant}%0AEmail: ${email}%0APackage: ${pkg}%0AMessage: ${msg}`;
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={onClose} className="absolute inset-0 bg-black/90 backdrop-blur-sm" />
      <motion.div initial={{ scale: 0.9, opacity: 0, y: 20 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.9, opacity: 0, y: 20 }} className="relative bg-[#141310] border border-white/10 p-8 md:p-12 max-w-lg w-full rounded-2xl shadow-2xl overflow-hidden">
        <button onClick={onClose} className="absolute top-6 right-6 text-white/40 hover:text-white transition-colors"><X size={24} /></button>
        <div className="relative z-10">
          <h3 className="text-4xl font-black text-white tracking-tighter mb-2 uppercase">Let's Get Started</h3>
          <p className="text-white/60 mb-8">Tell us about your restaurant. We'll take it from here.</p>
          <form className="space-y-4" onSubmit={handleSubmit}>
            <div>
              <label className="block text-[10px] uppercase tracking-[0.2em] font-bold text-white/40 mb-2">Restaurant Name</label>
              <input name="restaurant" type="text" className="w-full bg-black border border-white/10 rounded-lg p-4 text-white outline-none focus:border-red-600 transition-colors" placeholder="e.g. Taco Loco" required />
            </div>
            <div>
              <label className="block text-[10px] uppercase tracking-[0.2em] font-bold text-white/40 mb-2">Email Address</label>
              <input name="email" type="email" className="w-full bg-black border border-white/10 rounded-lg p-4 text-white outline-none focus:border-red-600 transition-colors" placeholder="you@restaurant.com" required />
            </div>
            <div>
              <label className="block text-[10px] uppercase tracking-[0.2em] font-bold text-white/40 mb-2">Package</label>
              <select name="package" className="w-full bg-black border border-white/10 rounded-lg p-4 text-white outline-none focus:border-red-600 transition-colors appearance-none">
                <option>Starter — $149 (1 dish, 3 videos)</option>
                <option>Core — $349 (2 dishes, 8 videos)</option>
                <option>Retainer — $999/mo (weekly drops)</option>
              </select>
            </div>
            <div>
              <label className="block text-[10px] uppercase tracking-[0.2em] font-bold text-white/40 mb-2">Tell Us About Your Dish</label>
              <textarea name="message" rows={3} className="w-full bg-black border border-white/10 rounded-lg p-4 text-white outline-none focus:border-red-600 transition-colors resize-none" placeholder="What dish are you promoting? Any special details?" />
            </div>
            <button type="submit" className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-4 rounded-lg transition-colors uppercase tracking-widest mt-4">
              Send Inquiry →
            </button>
          </form>
        </div>
      </motion.div>
    </div>
  );
};

